import React, {
  createContext,
  useContext,
  useState,
  useEffect,
  useCallback,
  useRef
} from 'react';
import { Connection, clusterApiUrl, Keypair, PublicKey } from '@solana/web3.js';

const AppContext = createContext();

// Simple localStorage wrapper with error handling
const storage = {
  get: (key) => {
    try {
      const item = localStorage.getItem('nexus_' + key);
      return item ? JSON.parse(item) : null;
    } catch (e) {
      console.error('Storage get error:', e);
      return null;
    }
  },
  set: (key, value) => {
    try {
      localStorage.setItem('nexus_' + key, JSON.stringify(value));
      return true;
    } catch (e) {
      console.error('Storage set error:', e);
      return false;
    }
  },
  remove: (key) => {
    try {
      localStorage.removeItem('nexus_' + key);
      return true;
    } catch (e) {
      console.error('Storage remove error:', e);
      return false;
    }
  },
  clear: () => {
    try {
      Object.keys(localStorage).forEach(key => {
        if (key.startsWith('nexus_')) {
          localStorage.removeItem(key);
        }
      });
      return true;
    } catch (e) {
      console.error('Storage clear error:', e);
      return false;
    }
  }
};

export function AppProvider({ children }) {
  const [network, setNetwork] = useState('devnet');
  const [connection, setConnection] = useState(null);
  const [wallets, setWallets] = useState([]);
  const [balances, setBalances] = useState({});
  const [deployedToken, setDeployedToken] = useState(null);
  const [logs, setLogs] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [loadError, setLoadError] = useState(null);

  const isMounted = useRef(true);
  const walletsRef = useRef(wallets);
  const initDone = useRef(false);

  useEffect(() => {
    walletsRef.current = wallets;
  }, [wallets]);

  useEffect(() => {
    try {
      const conn = new Connection(clusterApiUrl(network), 'confirmed');
      setConnection(conn);
      console.log('Connected to', network);
    } catch (err) {
      console.error('Failed to create connection:', err);
    }
  }, [network]);

  useEffect(() => {
    return () => {
      isMounted.current = false;
    };
  }, []);

  const addLog = useCallback((msg, type = 'info') => {
    if (!isMounted.current) return;
    const newLog = {
      msg,
      type,
      time: new Date().toLocaleTimeString()
    };
    setLogs(prev => [...prev, newLog]);
  }, []);

  const refreshBalances = useCallback(async () => {
    if (!connection || walletsRef.current.length === 0) {
      console.log('Skipping balance refresh - no connection or wallets');
      return;
    }

    console.log('Refreshing balances for', walletsRef.current.length, 'wallets');

    try {
      const newBalances = {};

      for (const w of walletsRef.current) {
        try {
          console.log('Fetching balance for', w.publicKey.slice(0, 8));
          const lamports = await connection.getBalance(new PublicKey(w.publicKey));
          newBalances[w.publicKey] = lamports / 1000000000;
          console.log('Balance:', newBalances[w.publicKey], 'SOL');
        } catch (err) {
          console.error('Failed to fetch balance for', w.publicKey, err);
          newBalances[w.publicKey] = 0;
        }
      }

      if (isMounted.current) {
        setBalances(newBalances);
        console.log('Balances updated:', newBalances);
      }
    } catch (err) {
      console.error('Balance refresh failed:', err);
      addLog('Failed to refresh balances', 'error');
    }
  }, [connection, addLog]);

  // Load data on mount only
  useEffect(() => {
    if (initDone.current) return;
    initDone.current = true;

    const loadData = () => {
      try {
        console.log('Loading from localStorage...');

        const savedWallets = storage.get('wallets');
        console.log('Saved wallets:', savedWallets);

        if (savedWallets && Array.isArray(savedWallets)) {
          const reconstructed = savedWallets.map((w, index) => {
            try {
              const keypair = Keypair.fromSecretKey(new Uint8Array(w.secretKey));
              return {
                name: w.name || 'Wallet ' + (index + 1),
                publicKey: w.publicKey,
                keypair: keypair
              };
            } catch (err) {
              console.error('Failed to reconstruct wallet:', err);
              return null;
            }
          }).filter(Boolean);

          if (isMounted.current) {
            setWallets(reconstructed);
            console.log('Loaded', reconstructed.length, 'wallets');
          }
        }

        const savedToken = storage.get('token');
        if (savedToken && isMounted.current) {
          setDeployedToken(savedToken);
        }

        const savedLogs = storage.get('logs');
        if (savedLogs && Array.isArray(savedLogs) && isMounted.current) {
          setLogs(savedLogs);
        } else if (isMounted.current) {
          setLogs([{
            msg: 'System initialized',
            type: 'success',
            time: new Date().toLocaleTimeString()
          }]);
        }

      } catch (err) {
        console.error('Load error:', err);
        setLoadError(err.message);
      } finally {
        setTimeout(() => {
          if (isMounted.current) {
            setIsLoading(false);
            console.log('Loading complete');
          }
        }, 500);
      }
    };

    setTimeout(() => {
      if (isMounted.current && isLoading) {
        console.log('Safety timeout - forcing load complete');
        setIsLoading(false);
      }
    }, 5000);

    loadData();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    if (isLoading) return;

    console.log('Saving wallets...', wallets.length);
    if (wallets.length === 0) {
      storage.remove('wallets');
    } else {
      const safeWallets = wallets.map(w => ({
        name: w.name,
        publicKey: w.publicKey,
        secretKey: Array.from(w.keypair.secretKey)
      }));
      const saved = storage.set('wallets', safeWallets);
      console.log('Save result:', saved);
    }
  }, [wallets, isLoading]);

  useEffect(() => {
    if (isLoading) return;

    if (deployedToken) {
      storage.set('token', deployedToken);
    } else {
      storage.remove('token');
    }
  }, [deployedToken, isLoading]);

  useEffect(() => {
    if (isLoading || logs.length === 0) return;

    const trimmed = logs.slice(-100);
    storage.set('logs', trimmed);
  }, [logs, isLoading]);

  const addWallet = useCallback(async (name) => {
    try {
      const newKeypair = Keypair.generate();
      const newWallet = {
        name: name || 'Wallet ' + (wallets.length + 1),
        publicKey: newKeypair.publicKey.toString(),
        keypair: newKeypair
      };

      setWallets(prev => [...prev, newWallet]);
      addLog('Created wallet: ' + newWallet.publicKey.slice(0, 8) + '...', 'success');
      return newWallet;
    } catch (err) {
      console.error('Failed to create wallet:', err);
      addLog('Failed to create wallet', 'error');
      return null;
    }
  }, [wallets.length, addLog]);

  const importWallet = useCallback(async (name, secretKey) => {
    try {
      const secretKeyArray = secretKey instanceof Uint8Array
        ? secretKey
        : new Uint8Array(secretKey);

      const keypair = Keypair.fromSecretKey(secretKeyArray);
      const newWallet = {
        name: name || 'Imported ' + (wallets.length + 1),
        publicKey: keypair.publicKey.toString(),
        keypair: keypair
      };

      if (wallets.some(w => w.publicKey === newWallet.publicKey)) {
        addLog('Wallet already exists', 'warning');
        return null;
      }

      setWallets(prev => [...prev, newWallet]);
      addLog('Imported wallet: ' + newWallet.publicKey.slice(0, 8) + '...', 'success');
      return newWallet;
    } catch (err) {
      console.error('Failed to import wallet:', err);
      addLog('Failed to import wallet: ' + err.message, 'error');
      return null;
    }
  }, [wallets.length, wallets, addLog]);

  const removeWallet = useCallback((publicKey) => {
    setWallets(prev => prev.filter(w => w.publicKey !== publicKey));
    setBalances(prev => {
      const newBalances = { ...prev };
      delete newBalances[publicKey];
      return newBalances;
    });
    addLog('Wallet removed', 'info');
  }, [addLog]);

  const clearAllData = useCallback(async () => {
    storage.clear();
    setWallets([]);
    setBalances({});
    setDeployedToken(null);
    setLogs([{
      msg: 'All data cleared',
      type: 'info',
      time: new Date().toLocaleTimeString()
    }]);
  }, [addLog]);

  const refreshWalletBalances = useCallback(() => {
    refreshBalances();
    addLog('Balances refreshed', 'info');
  }, [refreshBalances, addLog]);

  if (isLoading) {
    return (
      <div style={{ 
        padding: '20px', 
        textAlign: 'center',
        background: '#0a0a0f',
        color: '#00f3ff',
        minHeight: '100vh',
        display: 'flex',
        flexDirection: 'column',
        justifyContent: 'center',
        alignItems: 'center'
      }}>
        <h2>Loading Nexus...</h2>
        <p style={{ color: '#666', fontSize: '12px' }}>
          {loadError ? 'Error: ' + loadError : 'Loading...'}
        </p>
      </div>
    );
  }

  return (
    <AppContext.Provider value={{
      network,
      setNetwork,
      connection,
      wallets,
      balances,
      setWallets,
      addWallet,
      importWallet,
      removeWallet,
      deployedToken,
      setDeployedToken,
      logs,
      addLog,
      clearAllData,
      refreshWalletBalances
    }}>
      {children}
    </AppContext.Provider>
  );
}

export function useApp() {
  const context = useContext(AppContext);
  if (!context) {
    throw new Error('useApp must be used within AppProvider');
  }
  return context;
}
